import{c as a,Q as t,j as i,m as o}from"./chunks/framework.CdiUUa3G.js";const p=JSON.parse('{"title":"UXS-005 — Earth Orbit Viewer","description":"","frontmatter":{},"headers":[],"relativePath":"uxs/UXS-005.md","filePath":"uxs/UXS-005.md"}'),n={name:"uxs/UXS-005.md"};function l(s,e,r,c,h,d){return t(),i("div",null,[...e[0]||(e[0]=[o(`<h1 id="uxs-005-—-earth-orbit-viewer" tabindex="-1">UXS-005 — Earth Orbit Viewer <a class="header-anchor" href="#uxs-005-—-earth-orbit-viewer" aria-label="Permalink to &quot;UXS-005 — Earth Orbit Viewer&quot;">​</a></h1><blockquote><p>Status · Draft v0.1 Visual fidelity · Verified against prototype (P05_earth-orbit.html) IA anchor · §surfaces/earth · §topbar-patterns · §shared-tokens Related PRD · PRD-005</p></blockquote><h2 id="why-this-uxs-exists" tabindex="-1">Why this UXS exists <a class="header-anchor" href="#why-this-uxs-exists" aria-label="Permalink to &quot;Why this UXS exists&quot;">​</a></h2><p>The Earth orbit viewer is a single logarithmic-scale canvas. This UXS defines the scale function, object appearance, regime labels, and detail panel.</p><h2 id="principles" tabindex="-1">Principles <a class="header-anchor" href="#principles" aria-label="Permalink to &quot;Principles&quot;">​</a></h2><ul><li>The logarithmic scale must be legible without prior knowledge — labels explain the non-linearity</li><li>Object dots are small; labels are the signal</li><li>Regime bands are subtle — they frame, not overwhelm</li><li>The detail panel is the same component as explore and missions screens</li></ul><h2 id="scope" tabindex="-1">Scope <a class="header-anchor" href="#scope" aria-label="Permalink to &quot;Scope&quot;">​</a></h2><p>In scope: nav bar, canvas (scale, objects, regime labels, regime bands), detail panel. Non-goals: object animation (static view — objects don&#39;t move). Boundary note: click detection logic belongs in the screen module.</p><h2 id="theme" tabindex="-1">Theme <a class="header-anchor" href="#theme" aria-label="Permalink to &quot;Theme&quot;">​</a></h2><p>Dark only.</p><h2 id="tokens" tabindex="-1">Tokens <a class="header-anchor" href="#tokens" aria-label="Permalink to &quot;Tokens&quot;">​</a></h2><h3 id="inherited-from-ia" tabindex="-1">Inherited from IA <a class="header-anchor" href="#inherited-from-ia" aria-label="Permalink to &quot;Inherited from IA&quot;">​</a></h3><p>All shared tokens.</p><h3 id="defined-here" tabindex="-1">Defined here <a class="header-anchor" href="#defined-here" aria-label="Permalink to &quot;Defined here&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>regime-leo:    rgba(75,156,211,0.06)   Low Earth Orbit band</span></span>
<span class="line"><span>regime-meo:    rgba(68,102,255,0.05)   Medium Earth Orbit band</span></span>
<span class="line"><span>regime-geo:    rgba(255,200,80,0.06)   Geostationary band</span></span>
<span class="line"><span>regime-cis:    rgba(255,255,255,0.03)  Cislunar band</span></span>
<span class="line"><span>scale-fn:      altToVis(alt_km) = 38 + 54 * log10(1 + alt_km/100)   (px from Earth surface)</span></span>
<span class="line"><span>object-dot:    4–6px radius, object-specific colour</span></span>
<span class="line"><span>object-label:  Space Mono 8px, object colour, left of dot</span></span></code></pre></div><h2 id="layout" tabindex="-1">Layout <a class="header-anchor" href="#layout" aria-label="Permalink to &quot;Layout&quot;">​</a></h2><p>Vertical canvas filling the viewport (minus nav bar). Earth at bottom. Scale labels on left edge. Regime band labels on right edge. Objects as dots at their computed vertical position. Detail panel right 314px on object click.</p><h2 id="component-states" tabindex="-1">Component states <a class="header-anchor" href="#component-states" aria-label="Permalink to &quot;Component states&quot;">​</a></h2><p><strong>Object (default):</strong> dot with glow, label to the right <strong>Object (selected):</strong> larger dot, brighter glow, label bold, panel open <strong>Regime band (visible):</strong> subtle background colour fill, label right edge</p><h2 id="accessibility" tabindex="-1">Accessibility <a class="header-anchor" href="#accessibility" aria-label="Permalink to &quot;Accessibility&quot;">​</a></h2><p>Canvas: <code>aria-label=&quot;Earth orbit diagram on logarithmic scale from ISS at 408 km to JWST at 1.5 million km&quot;</code>.</p><h2 id="acceptance-criteria" tabindex="-1">Acceptance criteria <a class="header-anchor" href="#acceptance-criteria" aria-label="Permalink to &quot;Acceptance criteria&quot;">​</a></h2><ul><li>[ ] ISS at bottom (~408 km), JWST near top (~1.5M km) — relative positions correct</li><li>[ ] Moon correctly positioned between cislunar region and L2</li><li>[ ] Geostationary belt at ~35,786 km</li><li>[ ] Regime labels visible and correctly positioned</li><li>[ ] Clicking any object opens detail panel</li><li>[ ] Detail panel shows altitude, orbital period, launch date, description</li></ul><hr><h2 id="extension-—-gallery-learn-tabs-v0-1-10" tabindex="-1">Extension — GALLERY + LEARN tabs (v0.1.10) <a class="header-anchor" href="#extension-—-gallery-learn-tabs-v0-1-10" aria-label="Permalink to &quot;Extension — GALLERY + LEARN tabs (v0.1.10)&quot;">​</a></h2><p>The detail panel gains a tab system: OVERVIEW (existing content) · GALLERY · LEARN. CSS sourced from the shared <code>src/lib/styles/panel-tabs.css</code> introduced in v0.1.10.</p><h3 id="layout-1" tabindex="-1">Layout <a class="header-anchor" href="#layout-1" aria-label="Permalink to &quot;Layout&quot;">​</a></h3><ul><li>Tabs row sits below the agency-row + name + status header, above the existing data grid.</li><li>GALLERY tab renders only when <code>static/data/earth-object-galleries.json[id] &gt; 0</code>. LEARN tab renders only when the earth-object record has non-empty <code>links[]</code>.</li><li>Lightbox dimisses on click anywhere; localised aria-label <code>panel_lightbox_close</code>.</li></ul><h3 id="tokens-extension" tabindex="-1">Tokens (extension) <a class="header-anchor" href="#tokens-extension" aria-label="Permalink to &quot;Tokens (extension)&quot;">​</a></h3><p>Inherits all panel-tab tokens from UXS-004 §Extension. Active tab border: <code>#4466ff</code>. GALLERY thumb hover border: <code>rgba(68, 102, 255, 0.6)</code>. LEARN tier accent colors: teal (intro) · blue (core) · gold (deep).</p><h3 id="acceptance-criteria-extension" tabindex="-1">Acceptance criteria (extension) <a class="header-anchor" href="#acceptance-criteria-extension" aria-label="Permalink to &quot;Acceptance criteria (extension)&quot;">​</a></h3><ul><li>[ ] OVERVIEW tab content (existing data grid + scale-fact + description + credit) unchanged</li><li>[ ] GALLERY tab renders when manifest count &gt; 0; thumbnail click opens lightbox</li><li>[ ] LEARN tab renders tiered intro/core/deep links from <code>earth-object.links</code></li><li>[ ] No GALLERY/LEARN tab when there&#39;s no data — never empty placeholders</li></ul>`,32)])])}const u=a(n,[["render",l]]);export{p as __pageData,u as default};
